const bcrypt = require('bcrypt')

const config = require('../config/index')
const { dataSource } = require('../db/data-source')
const logger = require('../utils/logger')('UsersController')
const generateJWT = require('../utils/generateJWT')

const passwordPattern = /(?=.*\d)(?=.*[a-z])(?=.*[A-Z]).{8,32}/
const emailPattern = /^[A-Za-z0-9._%+\\-]+@[A-Za-z0-9.\\-]+\.[A-Za-z]{2,}$/

function isUndefined (value) {
  return value === undefined
}

function isNotValidSting (value) {
  return typeof value !== 'string' || value.trim().length === 0 || value === ''
}

class UsersController {
  static async postSignup (req, res, next) {
    try {
      const { name, email, password } = req.body
      if (isUndefined(name) || isNotValidSting(name) || name.trim().length > 10 || name.trim().length < 2 ||
        isUndefined(email) || isNotValidSting(email) || !emailPattern.test(email) ||
        isUndefined(password) || isNotValidSting(password)) {
        logger.warn('Fields not filled correctly')
        res.status(400).json({
          message: 'Fields not filled correctly'
        })
        return
      }
      if (!passwordPattern.test(password)) {
        logger.warn('Failed to create user: password does not match rules')
        res.status(400).json({
          message: 'Password must contain uppercase, lowercase, and digits, 8-32 characters'
        })
        return
      }
      const userRepository = dataSource.getRepository('users')
      const existingUser = await userRepository.findOne({
        where: { email }
      })

      if (existingUser) {
        logger.warn('Signup failed: email already in use')
        res.status(409).json({
          message: 'Signup failed: email already in use'
        })
        return
      }
      const salt = await bcrypt.genSalt(10)
      const hashPassword = await bcrypt.hash(password, salt)
      const newUser = userRepository.create({
        name,
        email,
        role: 'USER',
        password: hashPassword
      })
      const savedUser = await userRepository.save(newUser)
      logger.info('New user ID:', savedUser.id)
      res.status(201).json({
        message: 'Signup successful'
      })
    } catch (error) {
      logger.error('Failed to create user:', error)
      next(error)
    }
  }
}

module.exports = UsersController
